module down_counter(  
    input clk,  
    input reset,  
    input enable,  
    output reg [3:0] count  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset) begin  
            count <= 4'b1111;  
        end else if (!enable) begin  
            if (count == 4'b0000)  
                count <= 4'b1111;  
            else  
                count <= count - 1;  
        end  
    end  
endmodule
